// 1. Достаем данные профиля
const p = $items("Read_PROFILE")[0].json;
// 2. Достаем список задач
const tasks = $items("Read_Task_List");

// Работа с временем (Бангкок)
const now = DateTime.now().setZone('Asia/Bangkok');

// Функция для прогресс-баров
function createBar(value, size = 10) {
    const filled = Math.round(Math.min(Math.max(value, 0), 1) * size);
    return "█".repeat(filled) + "░".repeat(size - filled);
}

// --- БЛОК ЗАДАЧ ---
let taskList = "";
const validTasks = tasks.filter(item => {
    const taskName = item.json.TASK || item.json.Task || '';
    const st = String(item.json.STATUS || item.json.status || '').toLowerCase();
    return taskName && st !== '✅ completed' && st !== 'done' && st !== 'completed';
});
if (validTasks.length === 0) {
    taskList = "🎉 Все квесты на сегодня выполнены!";
} else {
    validTasks.forEach(item => {
        const t = item.json;
        const taskName = t.TASK || t.Task || '';
        const xpVal = t['XP| HP'] || t.REWARD_XP || 0;
        const priority = String(t.PRIORITY || t.Priority || '').toLowerCase();
        const icon = priority.includes('high') ? "🔥" : "📍";
        taskList += `${icon} ${taskName} (${xpVal} XP)\n`;
    });
}

// --- БЛОК ДЕБАФФОВ ---
let debuffBlock = "";
if (p.DEBUFF_EXPIRES) {
    const expires = DateTime.fromFormat(p.DEBUFF_EXPIRES, "yyyy-MM-dd HH:mm:ss", { zone: 'Asia/Bangkok' });
    if (now < expires) {
        const timeLeft = expires.diff(now, ['hours', 'minutes']).toObject();
        const timeStr = `${Math.floor(timeLeft.hours)}ч ${Math.floor(timeLeft.minutes)}м`;
        debuffBlock = `\n💀 **АКТИВНЫЙ ДЕБАФФ:**\n└ ${p.DEBUFF_NAME || "Проклятие Босса"}\n└ Спадёт через: ${timeStr}\n`;
    }
}

// --- БЛОК БОССА ---
const bossName = p.BOSS_NAME || '';
const bossBlock = bossName
    ? `⚔️ **ТЕКУЩИЙ БОСС:** ${bossName}\n${debuffBlock}`
    : '';

// --- ФИНАЛЬНЫЙ РЕНДЕР ---
const hpCurrent = Number(p.HP_CURRENT) || 0;
const totalProgress = Number(p.TOTAL_PROGRESS) || 0;
const isLevelReady = String(p.LEVEL_READY || '').toUpperCase() === 'TRUE';

const message = `
📊 **ЛИЧНЫЙ КАБИНЕТ: ${p.PLAYER_STAGE || '—'}**

❤️ **HP:** ${hpCurrent}/100 [${createBar(hpCurrent / 100)}]
✨ **Прогресс уровня:** ${Math.round(totalProgress * 100)}% [${createBar(totalProgress)}]

${bossBlock}──────────────────
📜 **АКТИВНЫЕ КВЕСТЫ:**
${taskList}──────────────────

${isLevelReady ? "🌟 **ПЕРЕХОД ДОСТУПЕН!**\nИспользуй /level_up" : ""}
`.trim();

return { lk_message: message };
